VALUES
  ('elementary-10ced7e2-moex-00451', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '罔市今年70餘歲，她和弟弟命運截然不同，出嫁時父親告訴她不能和弟弟一樣列名族譜，母親說她出嫁 後就不能回去祭祖。父親過世後弟弟要求她主動放棄爸爸的遺產繼承，以我國現行法令來看，若她向法 院或行政主管機關提出救濟，罔市下列主張何者最可能成立？', '["主張罔市這個名字侵害她的姓名權", "不得列名族譜侵害她親權行使權利", "不得回家祭祖限制了她的宗教自由", "弟弟要她放棄遺產侵害她的繼承權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00452', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '下列何種法律行為，即使不以書面為之，仍具法律效力？', '["機車租賃", "房屋買賣", "限定繼承", "同性伴侶結婚"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00453', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '疫情蔓延期間，為避免密閉空間感染風險，民眾搭乘大眾運輸未戴口罩，業者可先進行勸導，如勸導不 聽可拒載，政府並得依《傳染病防治法》向民眾開罰。下列解釋何者正確？', '["民眾未戴口罩，經勸導不聽而被罰，可能會侵害到民眾的社會權", "政府對民眾開罰的依據，須經立法程序，為建構有限政府的條件", "民眾違規被罰，因於疫情蔓延期間，民眾即無申訴及答辯的機會", "政府依法律授權，對違反規定的民眾開罰，稱之為「政治責任」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00454', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '我國某直轄市政府為打造友善環境生態，參考民間團體的意見與其他縣市政府的作法，希望透過自治條 例規範非農業用地全面禁止使用除草劑，若查獲違規案件將依規定處罰。前述法規涉及各層級政府權責 及地方治理，下列敘述何者正確？', '["市政府引進第三部門參與政府的公共服務", "屬於地方自治與跨縣市區域經營合辦事項", "屬中央政府委由地方政府代為辦理的事項", "該項法規必須經該直轄市市議會議決通過"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00455', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '下列被我國大法官宣告違憲的法規中，何者並非基於保障人民的「平等權」而做出違憲宣告？', '["《少年事件處理法》規定「就常逃學逃家虞犯少年裁定收容感化教育」違憲", "《身心障礙者保護法》規定「非本法所稱之視障者，不得從事按摩業」違憲", "《民法》規定「父母對於未成年子女權利之行使意思不一致時，由父行使之」違憲", "民法規定「未能使相同性別二人結婚」違憲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00456', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '立法院通過《憲法訴訟法》，將違憲審查與解釋法律及命令的任務由司法院大法官組成的憲法法庭來負 責，並於2022年1月4日正式實施。下列敘述何者正確？', '["違法失職的公務員案件亦是由憲法法庭審理", "大法官產生方式與行政院院長及檢察總長相同", "憲法法庭的審理規則由立法院訂定之", "憲法法庭審理案件由司法院院長擔任審判長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00457', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '下列那一個國際組織為聯合國管轄的國際金融機構，目的在提供各國經濟發展與掃除貧窮的貸款援助。 自1963年開始援助中低收入國家教育政策與實務，而援助方案較強調對初、中等教育及基礎教育的援助？', '["世界銀行（WorldBank）", "世界貿易組織（WTO）", "北美自由貿易協定（NAFTA）", "經濟合作暨發展組織（OECD）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00458', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '依據憲法增修條文第 4 條之規定，依政黨比例代表制所選任之不分區立法委員，倘若就職後喪失原政黨 籍，下列處理方式何者正確？', '["喪失立法委員身分，缺額由該政黨登記之候選人名單按順位依序遞補", "立法委員身分與席次均不受影響，以無黨籍或其他黨籍維持就任狀態", "立法委員身分與席次均不受影響，但原政黨得依法對其提出罷免連署", "喪失立法委員身分，缺額由原政黨指定人選出任，不受原候選人名單限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00459', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '人民可以透過參與各種團體的方式來影響政府的政策或立法，而人民最常參與的團體是政黨與利益團 體。關於這兩種團體之比較何者錯誤？', '["政黨可以收取政治獻金；利益團體無法收取政治獻金", "政黨以爭取執政為目的；利益團體則以影響公共政策為目的", "政黨的主張較全面且富有彈性；利益團體的主張則較為明確、固定", "政黨會針對特定公共政策進行遊說；利益團體則著重調和不同團體的利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00460', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '行政法泛指國家行政所適用之法規，包括行政組織、行政程序、行政救濟等規範。在我國，下列何者不 是行政法規範的範圍？', '["行政院院長提出公平交易委員會委員名單", "最高法院宣告觸犯殺人罪之被告死刑判決", "考選部公布今年度初等考試合格錄取名單", "臺東縣稅務局於每一張電影票課徵娛樂稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
